import React from "react";
import styleMesseg from "./Messeg.module.css";

const Messeg = (props) => {
  const messegMap = props.text.map((e) => {
    <li className={styleMesseg.container__list_messeg}>{e.messege}</li>;
  });

  return (
    <div className={styleMesseg.container}>
      <ul className={styleMesseg.container__list}>{messegMap}</ul>
    </div>
  );
};

export default Messeg;
